import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { ClientService } from "src/app/core/services/client.service";
import { InstallmentsService } from "src/app/core/services/installments.service";
import { LoansService } from "src/app/core/services/loans.service";
import { pagingService } from "src/app/core/services/paging.service";
import { TransactionService } from "src/app/core/services/transaction.service";
import { ClientInfoData } from "src/app/views/Models/Client/ClientInfoData";
import { GetInstallmentInformationByInstallmentKey } from "src/app/views/Models/Installments/getInstallmentInformationByInstallmentKey";
import { GetLoanInformationByLoanKey } from "src/app/views/Models/Loan/GetLoanInformationByLoanKey";
import { AccessRight } from "src/app/views/Models/Permissions/AccessRight";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import { GetInsertedCancellationPenaltyTransactionsByClientKey } from "src/app/views/Models/Transaction/GetInsertedCancellationPenaltyTransactionsByClientKey";
import { GetTransactionInformationByTransactionCode } from "src/app/views/Models/Transaction/GetTransactionInformationByTransactionCode";
import { GetUnexecutedCancellationPenaltyByClientKey } from "src/app/views/Models/Transaction/GetUnexecutedCancellationPenaltyByClientKey";
import * as customValidators from "src/app/core/validators/custom-validators";
import { HttpErrorResponse } from "@angular/common/http";
import { SegmentCustomEvent } from "@ionic/angular";
import { UpdateInsertedCancellationPenaltyTransactions } from "src/app/views/Models/Transaction/UpdateInsertedCancellationPenaltyTransactions";
import { DeleteInsertedCancellationPenaltyTransactions } from "src/app/views/Models/Transaction/DeleteInsertedCancellationPenaltyTransactions";
import { InsertUnexecutedCancellationPenalty } from "src/app/views/Models/Transaction/InsertUnexecutedCancellationPenalty";

interface segmentInformation {
  name: string;
  sourcePage: number;
  pageAction: number;
  windowCode: string;
  hasPermission: boolean;
}
interface SegmentSection {
  visible: boolean;
  allAvaliableSegments: segmentInformation[];
  selectedSegment: segmentInformation;
  disable: boolean;
}
interface ClientSearchSection {
  visible: boolean;
  clientInformation: SearchResult;
}
interface GridSection {
  insert: {
    visible: boolean;
    gridInformation: GetUnexecutedCancellationPenaltyByClientKey[];
  };
  edit: {
    visible: boolean;
    gridInformation: GetInsertedCancellationPenaltyTransactionsByClientKey[];
  };
  delete: {
    visible: boolean;
    gridInformation: GetInsertedCancellationPenaltyTransactionsByClientKey[];
  };
}
interface ReadonlyInformation {
  clientName: string;
  branchCode: number;
  clientCode: number;
  loanCode: number;
  loanDate: string;
  loanStatusName: string;
  loanAmount: number;
  loanInterest: number;
  loanPenaltyAmount: number;
  transactionCode: number;
  transactionAmount: number;
  penaltyTypeDescription: string;
  safeName: string;
  funderName: string;
  issuingBankName: string;
  transactionActualDate: string;
}
interface ClientSection {
  visible: boolean;
  formGroup: FormGroup;
  checkIfInputsValid: boolean;
  readonlyInformation: ReadonlyInformation;
}
interface DatabasesResponses {
  accessRight: AccessRight[];
  clientInformation: ClientInfoData;
  loanInformation: GetLoanInformationByLoanKey;
  installmentInformation: GetInstallmentInformationByInstallmentKey;
  transactionInformation: GetTransactionInformationByTransactionCode;
}
@Component({
  selector: "app-unexecuted-cancellation-penalty",
  templateUrl: "./unexecuted-cancellation-penalty.page.html",
  styleUrls: ["./unexecuted-cancellation-penalty.page.scss"],
})
export class UnexecutedCancellationPenaltyPage implements OnInit {
  constructor(
    private alertService: AlertService,
    private authService: MohassilAuthService,
    private transactionService: TransactionService,
    public pagingService: pagingService,
    private formBuilder: FormBuilder,
    private clientService: ClientService,
    private loanService: LoansService,
    private installmentService: InstallmentsService
  ) {}
  //#region Variables
  showLoader: boolean = false;
  segmentSection: SegmentSection;
  clientSearchCardSection: ClientSearchSection;
  gridCardSection: GridSection;
  clientSection: ClientSection;
  databaseResponses: DatabasesResponses;
  pagingObject: { page: number };
  //#endregion

  get allSegmentsThatHavePermission() {
    return this.segmentSection.allAvaliableSegments.filter(
      (x) => x.hasPermission
    );
  }
  get readonlyInformation(): ReadonlyInformation {
    return this.clientSection.readonlyInformation;
  }
  async ngOnInit() {
    this.initializeState();
    this.databaseResponses.accessRight =
      await this.authService.getAccessRights();
    this.segmentSection = {
      visible: true,
      allAvaliableSegments: [
        {
          name: "ادخال حركة",
          sourcePage: 26,
          pageAction: 1,
          windowCode: "5646",
          hasPermission: this.databaseResponses.accessRight.some(
            (x) => x.window_code === "5646"
          ),
        },
        {
          name: "تعديل حركة",
          sourcePage: 27,
          pageAction: 0,
          windowCode: "5647",
          hasPermission: this.databaseResponses.accessRight.some(
            (x) => x.window_code === "5647"
          ),
        },
        {
          name: "حذف حركة",
          sourcePage: 25,
          pageAction: 0,
          windowCode: "5648",
          hasPermission: this.databaseResponses.accessRight.some(
            (x) => x.window_code === "5648"
          ),
        },
      ],
      selectedSegment: null,
      disable: false,
    };
    this.segmentSection.selectedSegment =
      this.segmentSection.allAvaliableSegments.find((x) => x.hasPermission);
  }
  async initializeState() {
    this.segmentSection = {
      allAvaliableSegments: [],
      disable: false,
      selectedSegment: null,
      visible: false,
    };
    this.clientSearchCardSection = {
      clientInformation: null,
      visible: true,
    };
    this.databaseResponses = {
      accessRight: [],
      clientInformation: null,
      loanInformation: null,
      installmentInformation: null,
      transactionInformation: null,
    };
    this.clientSection = {
      checkIfInputsValid: false,
      formGroup: this.formBuilder.group({
        transactionVoucher: [null],
        transactionDate: [
          null,
          customValidators.dateTypeStringValidator({ required: true }),
        ],
      }),
      readonlyInformation: null,
      visible: false,
    };
    this.gridCardSection = {
      insert: {
        visible: false,
        gridInformation: [],
      },
      edit: {
        visible: false,
        gridInformation: [],
      },
      delete: {
        visible: false,
        gridInformation: [],
      },
    };
    this.pagingObject = {
      page: 1,
    };
  }
  async clientSelected(searchResult: SearchResult) {
    try {
      this.showLoader = true;
      this.clientSearchCardSection.clientInformation = searchResult;
      this.changePaginationPage(1);
      switch (this.segmentSection.selectedSegment.windowCode) {
        case "5646": {
          await this.insertSegment(searchResult);
          break;
        }
        case "5647": {
          await this.editSegment(searchResult);
          break;
        }
        case "5648": {
          await this.deleteSegment(searchResult);
          break;
        }
      }
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  changePaginationPage = async (newPage: number) => {
    this.pagingObject.page = newPage;
  };
  async insertSegment(searchResult: SearchResult) {
    this.gridCardSection.insert.gridInformation = await this.transactionService
      .getUnexecutedCancellationPenaltyByClientKey(searchResult.client_key)
      .toPromise();
    if (this.gridCardSection.insert.gridInformation.length === 0) {
      this.alertService.showAlertError("لا يوجد معلومات", false);
      return;
    }
    this.clientSearchCardSection.visible = false;
    this.gridCardSection.insert.visible = true;
    this.segmentSection.disable = true;
  }
  async editSegment(searchResult: SearchResult) {
    this.gridCardSection.edit.gridInformation = await this.transactionService
      .getInsertedCancellationPenaltyTransactionsByClientKey(
        searchResult.client_key
      )
      .toPromise();
    if (this.gridCardSection.edit.gridInformation.length === 0) {
      this.alertService.showAlertError("لا يوجد معلومات", false);
      return;
    }
    this.clientSearchCardSection.visible = false;
    this.gridCardSection.edit.visible = true;
    this.segmentSection.disable = true;
  }
  async deleteSegment(searchResult: SearchResult) {
    this.gridCardSection.delete.gridInformation = await this.transactionService
      .getInsertedCancellationPenaltyTransactionsByClientKey(
        searchResult.client_key
      )
      .toPromise();
    if (this.gridCardSection.delete.gridInformation.length === 0) {
      this.alertService.showAlertError("لا يوجد معلومات", false);
      return;
    }
    this.clientSearchCardSection.visible = false;
    this.gridCardSection.delete.visible = true;
    this.segmentSection.disable = true;
  }
  async initiatePenaltyForTransaction(transactionCode: number) {
    try {
      this.showLoader = true;
      this.clientSection.readonlyInformation =
        await this.extractReadOnlyInformation(transactionCode);
      this.gridCardSection.insert.visible = false;
      this.clientSection.visible = true;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async editingTransaction(transactionCode: number) {
    try {
      this.showLoader = true;
      this.clientSection.readonlyInformation =
        await this.extractReadOnlyInformation(transactionCode);
      const valuesToPatch = this.gridCardSection.edit.gridInformation.find(
        (x) => x.transactionCode === transactionCode
      );
      this.clientSection.formGroup.patchValue({
        transactionVoucher:
          !valuesToPatch.transactionVoucher ||
          valuesToPatch.transactionVoucher.trim() === ""
            ? null
            : valuesToPatch.transactionVoucher,
        transactionDate: valuesToPatch.transactionDate,
      });
      this.gridCardSection.edit.visible = false;
      this.clientSection.visible = true;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  transactionSegmentChanging(event: any): void {
    const segmentEvent = event as SegmentCustomEvent;
    this.setSelectedTransactionSegment(segmentEvent.detail.value);
    this.resetClientSearchComponent();
  }
  setSelectedTransactionSegment(windowCode: string) {
    this.segmentSection.selectedSegment =
      this.segmentSection.allAvaliableSegments.find(
        (x) => x.windowCode === windowCode
      );
  }
  resetClientSearchComponent() {
    this.clientSearchCardSection.visible = false;
    setTimeout(() => (this.clientSearchCardSection.visible = true), 0);
  }
  async extractReadOnlyInformation(
    transactionCode: number
  ): Promise<ReadonlyInformation> {
    this.databaseResponses.transactionInformation =
      await this.transactionService
        .getTransactionInformationByTransactionCode(transactionCode)
        .toPromise();
    this.databaseResponses.clientInformation =
      await this.clientService.getClientInfoByClientKey(
        this.databaseResponses.transactionInformation.clientKey
      );
    this.databaseResponses.loanInformation = await this.loanService
      .getLoanInformationByLoanKey(
        this.databaseResponses.transactionInformation.loanKey
      )
      .toPromise();
    const { transactionInformation, clientInformation, loanInformation } =
      this.databaseResponses;
    return {
      branchCode: transactionInformation.branchCode,
      clientName: clientInformation.clientName,
      clientCode: transactionInformation.clientCode,
      funderName: transactionInformation.funderName,
      transactionCode: transactionInformation.transactionCode,
      transactionActualDate: transactionInformation.transactionActualDate,
      loanAmount: loanInformation.loanAmount,
      loanDate: loanInformation.loanDate,
      loanCode: loanInformation.loanCode,
      loanInterest: loanInformation.loanInterestAmount,
      loanPenaltyAmount: loanInformation.loanPenalties,
      loanStatusName: loanInformation.loanStatusName,
      penaltyTypeDescription:
        transactionInformation.transactionLoanPenaltyTypeDescription,
      issuingBankName: loanInformation.bankName,
      transactionAmount: transactionInformation.transactionLoanPenalty,
      safeName: transactionInformation.transactionCurrentBankDescription,
    };
  }
  backButton() {
    // ClientCardSection ==> GridSection
    if (this.clientSection.visible) {
      this.clientSection.visible = false;
      this.clientSection.checkIfInputsValid = false;
      if (this.gridCardSection.insert.gridInformation.length)
        this.gridCardSection.insert.visible = true;
      if (this.gridCardSection.edit.gridInformation.length)
        this.gridCardSection.edit.visible = true;
      if (this.gridCardSection.delete.gridInformation.length)
        this.gridCardSection.delete.visible = true;
      this.clientSection.formGroup.reset();
      this.databaseResponses.clientInformation = null;
      this.databaseResponses.loanInformation = null;
      this.databaseResponses.installmentInformation = null;
      this.databaseResponses.transactionInformation = null;
      return;
    }
    // GridSection ==> ClientSearchSection
    if (this.gridCardSection.insert.visible) {
      this.gridCardSection.insert.visible = false;
      this.gridCardSection.insert.gridInformation = [];
      this.clientSection.readonlyInformation = null;
      this.clientSearchCardSection = {
        visible: true,
        clientInformation: null,
      };
      this.segmentSection.disable = false;
      return;
    } else if (this.gridCardSection.edit.visible) {
      this.gridCardSection.edit.visible = false;
      this.gridCardSection.edit.gridInformation = [];
      this.clientSection.readonlyInformation = null;
      this.clientSearchCardSection = {
        visible: true,
        clientInformation: null,
      };
      this.segmentSection.disable = false;
      return;
    } else if (this.gridCardSection.delete.visible) {
      this.gridCardSection.delete.visible = false;
      this.gridCardSection.delete.gridInformation = [];
      this.clientSection.readonlyInformation = null;
      this.clientSearchCardSection = {
        visible: true,
        clientInformation: null,
      };
      this.segmentSection.disable = false;
      return;
    }
  }
  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
  async insertTransactionButton() {
    try {
      this.clientSection.checkIfInputsValid = true;
      if (!this.clientSection.formGroup.valid) return;
      if (!(await this.alertService.SaveAlert())) return;
      this.showLoader = true;
      const { value } = this.clientSection.formGroup;
      const request: InsertUnexecutedCancellationPenalty = {
        transactionActualCancelDate: value.transactionDate,
        transactionCode: this.readonlyInformation.transactionCode,
        transactionInstallmentVoucher: value.transactionVoucher,
        transactionUuc:
          this.databaseResponses.transactionInformation.transactionUuc,
      };
      await this.transactionService
        .insertUnexecutedCancellationPenalty(request)
        .toPromise();
      this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async updateTransactionButton() {
    try {
      this.clientSection.checkIfInputsValid = true;
      if (!this.clientSection.formGroup.valid) return;
      if (!(await this.alertService.SaveAlert())) return;
      this.showLoader = true;
      const { value } = this.clientSection.formGroup;
      const request: UpdateInsertedCancellationPenaltyTransactions = {
        transactionActualDate: value.transactionDate,
        transactionCode: this.readonlyInformation.transactionCode,
        transactionUuc:
          this.databaseResponses.transactionInformation.transactionUuc,
        transactionVoucher:
          !value.transactionVoucher || value.transactionVoucher.trim() === ""
            ? null
            : value.transactionVoucher,
      };
      await this.transactionService
        .updateInsertedCancellationPenaltyTransactions(request)
        .toPromise();
      this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async deleteTransactionButton(transactionCode: number) {
    try {
      if (!(await this.alertService.SaveAlert())) return;
      this.showLoader = true;
      this.clientSection.readonlyInformation =
        await this.extractReadOnlyInformation(transactionCode);

      const request: DeleteInsertedCancellationPenaltyTransactions = {
        transactionCode: this.readonlyInformation.transactionCode,
        transactionUuc:
          this.databaseResponses.transactionInformation.transactionUuc,
      };

      await this.transactionService
        .deleteInsertedCancellationPenaltyTransactions(request)
        .toPromise();
      this.alertService.showAlertConfirm("تم الحفظ", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
}
